/**
 * RouterWorker - Auto-generates HTTP endpoints from @CommandHandler decorators
 *
 * This worker automatically discovers command handlers via the COMMAND_HANDLERS
 * registry and creates corresponding HTTP endpoints. Each endpoint forwards
 * requests to the appropriate Durable Object for command execution.
 *
 * @packageDocumentation
 */

import { Hono } from 'hono';
import type { Context } from 'hono';
import { getCommandHandlers } from '../decorators/CommandHandler';

/**
 * Environment bindings for Durable Object namespaces
 */
export interface RouterWorkerEnv {
  [key: string]: any;
  BANK_ACCOUNT_DO?: DurableObjectNamespace;
  USER_PROFILE_DO?: DurableObjectNamespace;
  // Add more DO namespaces as needed
}

/**
 * Router Worker - Auto-generates endpoints and forwards to Durable Objects
 *
 * This class scans the COMMAND_HANDLERS registry created by @CommandHandler
 * decorators and automatically creates HTTP endpoints for each command.
 * Requests are forwarded to the appropriate Durable Object instance based
 * on the aggregate type and aggregate ID.
 *
 * @example
 * ```typescript
 * // In your worker entry point:
 * import { RouterWorker } from 'ceves';
 * import './commands/CreateAccountHandler';
 * import './commands/DebitAccountHandler';
 *
 * export default {
 *   async fetch(request: Request, env: Env): Promise<Response> {
 *     const router = new RouterWorker(env);
 *     return router.fetch(request);
 *   }
 * };
 * ```
 */
export class RouterWorker {
  private app: Hono;
  private env: RouterWorkerEnv;

  /**
   * Create RouterWorker and auto-register all command endpoints
   *
   * @param env - Cloudflare environment with DO namespace bindings
   */
  constructor(env: RouterWorkerEnv) {
    this.env = env;
    this.app = new Hono();
    this.registerCommandEndpoints();
  }

  /**
   * Auto-register HTTP endpoints from COMMAND_HANDLERS registry
   *
   * Scans all handlers registered via @CommandHandler decorator and creates
   * corresponding HTTP endpoints that forward to Durable Objects.
   */
  private registerCommandEndpoints(): void {
    const handlers = getCommandHandlers();

    if (handlers.size === 0) {
      console.warn('[RouterWorker] No command handlers registered. Did you import your handler files?');
    }

    for (const [, metadata] of handlers) {
      const { route, aggregateType, doBinding, method = 'POST' } = metadata;

      console.log(`[RouterWorker] Registering: ${method} ${route} → ${aggregateType} (${doBinding})`);

      // Create endpoint that forwards to DO
      this.app.on(method.toLowerCase() as any, route, async (c: Context) => {
        return this.forwardToDurableObject(c, doBinding);
      });
    }
  }

  /**
   * Forward request to appropriate Durable Object
   *
   * Extracts aggregateId from request (params, body, or query) and forwards
   * the entire request to the corresponding Durable Object instance.
   *
   * @param c - Hono context
   * @param doBinding - DO binding name (e.g., 'BANK_ACCOUNT')
   * @returns Response from Durable Object
   */
  private async forwardToDurableObject(
    c: Context,
    doBinding: string
  ): Promise<Response> {
    try {
      // Extract aggregateId from request
      // Priority: 1) Path params (:id, :aggregateId), 2) Body, 3) Query
      const params = c.req.param();
      let aggregateId = params.id || params.aggregateId;

      // If not in params, try body
      if (!aggregateId) {
        try {
          const body = await c.req.json();
          aggregateId = body.aggregateId || body.id;
        } catch (e) {
          // Body might not be JSON, that's okay
        }
      }

      // If still not found, try query params
      if (!aggregateId) {
        const query = c.req.query();
        aggregateId = query.aggregateId || query.id;
      }

      if (!aggregateId) {
        return c.json(
          {
            success: false,
            error: 'Missing aggregateId',
            message: 'aggregateId must be provided in path params, body, or query string',
          },
          400
        );
      }

      // Get Durable Object stub
      const doStub = this.getDurableObjectStub(doBinding, aggregateId);

      // Forward entire request to DO
      // DO will handle command execution with in-memory state
      return doStub.fetch(c.req.raw);
    } catch (error) {
      console.error('[RouterWorker] Error forwarding to DO:', error);

      return c.json(
        {
          success: false,
          error: 'Routing error',
          message: error instanceof Error ? error.message : 'Unknown error',
        },
        500
      );
    }
  }

  /**
   * Get Durable Object stub for DO binding
   *
   * Looks up DO namespace from environment bindings and creates deterministic
   * DO ID from aggregateId using idFromName().
   *
   * @param doBinding - DO binding name (e.g., 'BANK_ACCOUNT')
   * @param aggregateId - Unique aggregate identifier
   * @returns Durable Object stub
   * @throws Error if no namespace configured for binding
   *
   * @example
   * ```typescript
   * // wrangler.toml configuration:
   * [[durable_objects.bindings]]
   * name = "BANK_ACCOUNT"
   * class_name = "BankAccountAggregate"
   * ```
   */
  private getDurableObjectStub(
    doBinding: string,
    aggregateId: string
  ): DurableObjectStub {
    // Look up DO namespace from environment using binding name
    const namespace = this.env[doBinding] as DurableObjectNamespace | undefined;

    if (!namespace) {
      throw new Error(
        `No Durable Object namespace found for binding "${doBinding}". ` +
          `Add binding to wrangler.toml:\n\n` +
          `[[durable_objects.bindings]]\n` +
          `name = "${doBinding}"\n` +
          `class_name = "YourAggregateClass"`
      );
    }

    // Create deterministic DO ID from aggregateId
    // Same aggregateId always maps to same DO instance
    const doId = namespace.idFromName(aggregateId);
    return namespace.get(doId);
  }

  /**
   * Handle incoming HTTP request
   *
   * @param request - Incoming HTTP request
   * @returns HTTP response from endpoint or Durable Object
   */
  async fetch(request: Request): Promise<Response> {
    return this.app.fetch(request);
  }

  /**
   * Get OpenAPI specification (generated from handler metadata)
   *
   * Future enhancement: Generate full OpenAPI 3.0 spec from
   * COMMAND_HANDLERS metadata (schemas, routes, descriptions)
   *
   * @returns OpenAPI schema object
   */
  getOpenAPISpec(): any {
    const handlers = getCommandHandlers();
    const paths: Record<string, any> = {};

    // Generate paths from handler metadata
    for (const [, metadata] of handlers) {
      const { route, method = 'POST', body, summary, description, tags, operationId, deprecated } = metadata;

      if (!paths[route]) {
        paths[route] = {};
      }

      paths[route][method.toLowerCase()] = {
        summary: summary || `Execute ${metadata.commandType} command`,
        description: description || '',
        tags: tags || [metadata.aggregateType],
        operationId: operationId || `${metadata.aggregateType}-${metadata.commandType}`,
        deprecated: deprecated || false,
        // TODO: Convert Zod schemas to OpenAPI schemas
        parameters: [],
        requestBody: body
          ? {
              required: true,
              content: {
                'application/json': {
                  schema: { type: 'object' }, // TODO: Convert Zod to OpenAPI
                },
              },
            }
          : undefined,
        responses: {
          200: {
            description: 'Success',
            content: {
              'application/json': {
                schema: { type: 'object' }, // TODO: Convert Zod to OpenAPI
              },
            },
          },
          400: {
            description: 'Bad Request',
          },
          404: {
            description: 'Not Found',
          },
          500: {
            description: 'Internal Server Error',
          },
        },
      };
    }

    return {
      openapi: '3.0.0',
      info: {
        title: 'Ceves Event Sourcing API',
        version: '1.0.0',
        description: 'Auto-generated API from @CommandHandler decorators',
      },
      paths,
    };
  }
}
