/**
 * Command Handler Decorator & Registry for Ceves Event Sourcing Library
 *
 * DO-first architecture: Command handlers are methods on aggregate classes.
 * This decorator registers methods as command handlers with full HTTP/OpenAPI metadata.
 *
 * @packageDocumentation
 */

import type { z } from 'zod';

/**
 * Metadata for command handler registration (DO-first mode)
 *
 * Stores all information needed for:
 * - Worker routing layer (route, method, schemas)
 * - DO method routing (commandType, methodName)
 * - OpenAPI documentation (summary, tags, etc.)
 */
export interface CommandHandlerMetadata {
  /** Command type identifier (e.g., 'OpenAccount', 'Withdraw') */
  commandType: string;

  /** Method name on the aggregate class (stored by decorator) */
  methodName: string;

  /** Aggregate type (derived from class name, e.g., 'BankAccountAggregate') */
  aggregateType: string;

  /**
   * Create command flag
   * - true: Command creates a new aggregate (state must be null)
   * - false: Command updates existing aggregate (state must exist)
   */
  createCommand: boolean;

  // HTTP/Routing metadata
  /** HTTP route pattern (e.g., '/accounts/:id/open') */
  route: string;

  /** HTTP method (default: POST) */
  method?: 'POST' | 'PUT' | 'DELETE' | 'GET' | 'PATCH';

  // OpenAPI/Validation schemas
  /** Request parameter schema (e.g., { id: z.string() }) */
  params?: z.ZodSchema;

  /** Request query schema */
  query?: z.ZodSchema;

  /** Request body schema */
  body?: z.ZodSchema;

  /** Request headers schema */
  headers?: z.ZodSchema;

  /** Response schemas by status code */
  responses?: Record<number, z.ZodSchema>;

  // OpenAPI documentation
  /** Short summary for OpenAPI docs */
  summary?: string;

  /** Detailed description for OpenAPI docs */
  description?: string;

  /** OpenAPI tags for grouping */
  tags?: string[];

  /** Mark as deprecated in OpenAPI */
  deprecated?: boolean;

  /** Unique operation ID for OpenAPI */
  operationId?: string;

  /**
   * Durable Object binding name (derived from aggregateType)
   * e.g., 'BankAccountAggregate' → 'BANK_ACCOUNT'
   */
  doBinding: string;
}

/**
 * Input metadata for @CommandHandler decorator
 * User provides this when decorating a method
 */
export type CommandHandlerInput = Omit<
  CommandHandlerMetadata,
  'methodName' | 'aggregateType' | 'doBinding'
>;

/**
 * Static registry storing all command handler methods with metadata.
 * Keyed by "${aggregateType}:${commandType}" for unique identification.
 *
 * @example
 * Key: "BankAccountAggregate:OpenAccount"
 * Value: { commandType: 'OpenAccount', methodName: 'openAccount', ... }
 */
const COMMAND_HANDLERS = new Map<string, CommandHandlerMetadata>();

/**
 * Command Handler decorator - DO-first architecture
 *
 * Decorates a method on an aggregate class to register it as a command handler.
 * The decorated method receives a command object and returns a domain event.
 *
 * **Infrastructure Handling:**
 * - State restoration happens BEFORE method is called (in AggregateObject.fetch)
 * - Event persistence happens AFTER method returns (in AggregateObject.fetch)
 * - Method just implements pure business logic
 *
 * **Method Signature:**
 * ```typescript
 * async methodName(command: TCommand): Promise<TEvent>
 * ```
 *
 * The method can access `this.state` directly from the aggregate.
 *
 * **Implementation Note:**
 * Uses legacy decorator syntax (experimentalDecorators: true) for Cloudflare Workers compatibility.
 * Stage 3 decorators with context.addInitializer are not supported in CF Workers runtime.
 *
 * @param metadata - Command handler configuration
 * @returns Method decorator function
 *
 * @example
 * ```typescript
 * export class BankAccountAggregate extends AggregateObject<AccountState> {
 *   @CommandHandler({
 *     commandType: 'OpenAccount',
 *     createCommand: true,
 *     route: '/accounts/:id/open',
 *     method: 'POST',
 *     params: z.object({ id: z.string() }),
 *     body: z.object({
 *       owner: z.string(),
 *       initialDeposit: z.number()
 *     }),
 *     responses: {
 *       201: z.object({ accountId: z.string(), version: z.number() })
 *     },
 *     summary: 'Open a new bank account',
 *     tags: ['Bank Account']
 *   })
 *   async openAccount(command: OpenAccountCommand): Promise<AccountOpenedEvent> {
 *     // Just business logic - infrastructure handled by base class
 *     return new AccountOpenedEvent(command.owner, command.initialDeposit);
 *   }
 *
 *   @CommandHandler({
 *     commandType: 'Withdraw',
 *     createCommand: false,
 *     route: '/accounts/:id/withdraw',
 *     method: 'POST',
 *     params: z.object({ id: z.string() }),
 *     body: z.object({ amount: z.number() })
 *   })
 *   async withdraw(command: WithdrawCommand): Promise<MoneyWithdrawnEvent> {
 *     // Can access this.state directly!
 *     if (this.state.balance < command.amount) {
 *       throw new BusinessRuleViolationError('Insufficient funds');
 *     }
 *     return new MoneyWithdrawnEvent(command.amount);
 *   }
 * }
 * ```
 */
export function CommandHandler(metadata: CommandHandlerInput) {
  return function (
    target: any,
    propertyKey: string,
    _descriptor: PropertyDescriptor
  ): void {
    // Legacy decorator signature: (target, propertyKey, descriptor)
    // target = prototype of the class
    // propertyKey = method name

    // Get aggregate type from the constructor
    const aggregateType = target.constructor.name;
    const doBinding = aggregateTypeToBinding(aggregateType);

    // Create full metadata
    const fullMetadata: CommandHandlerMetadata = {
      ...metadata,
      methodName: propertyKey,
      aggregateType,
      doBinding,
    };

    // Generate unique registry key
    const key = `${aggregateType}:${metadata.commandType}`;

    // Register handler immediately (legacy decorators execute at class definition time)
    if (!COMMAND_HANDLERS.has(key)) {
      COMMAND_HANDLERS.set(key, fullMetadata);
      console.log(
        `[CommandHandler] Registered: ${aggregateType}.${propertyKey}() as "${metadata.commandType}" → ${metadata.route}`
      );
    }
  };
}

/**
 * Convert aggregate type to DO binding name
 *
 * Naming convention:
 * - 'BankAccountAggregate' → 'BANK_ACCOUNT'
 * - 'OrderAggregate' → 'ORDER'
 * - 'UserProfileAggregate' → 'USER_PROFILE'
 *
 * @param aggregateType - Aggregate class name
 * @returns DO binding name (SCREAMING_SNAKE_CASE)
 *
 * @internal
 */
function aggregateTypeToBinding(aggregateType: string): string {
  // Remove 'Aggregate' suffix if present
  const withoutSuffix = aggregateType.replace(/Aggregate$/, '');

  // Convert PascalCase to SCREAMING_SNAKE_CASE
  return withoutSuffix
    .replace(/([A-Z])/g, '_$1')
    .toUpperCase()
    .replace(/^_/, '');
}

/**
 * Get all command handlers
 *
 * @returns Map of all registered command handlers
 *
 * @example
 * ```typescript
 * const handlers = getCommandHandlers();
 * for (const [key, metadata] of handlers) {
 *   console.log(`${metadata.aggregateType}.${metadata.methodName}() → ${metadata.route}`);
 * }
 * ```
 */
export function getCommandHandlers(): Map<string, CommandHandlerMetadata> {
  return COMMAND_HANDLERS;
}

/**
 * Get command handler by aggregate type and command type
 *
 * @param aggregateType - Aggregate class name (e.g., 'BankAccountAggregate')
 * @param commandType - Command type (e.g., 'OpenAccount')
 * @returns Command handler metadata or undefined
 *
 * @example
 * ```typescript
 * const handler = getCommandHandler('BankAccountAggregate', 'OpenAccount');
 * if (handler) {
 *   console.log(`Method: ${handler.methodName}`);
 *   console.log(`Route: ${handler.route}`);
 * }
 * ```
 */
export function getCommandHandler(
  aggregateType: string,
  commandType: string
): CommandHandlerMetadata | undefined {
  const key = `${aggregateType}:${commandType}`;
  return COMMAND_HANDLERS.get(key);
}

/**
 * Get all command handlers for a specific aggregate type
 *
 * @param aggregateType - Aggregate class name
 * @returns Array of command handler metadata for that aggregate
 *
 * @example
 * ```typescript
 * const handlers = getHandlersByAggregateType('BankAccountAggregate');
 * console.log(`Found ${handlers.length} command handlers`);
 * ```
 */
export function getHandlersByAggregateType(
  aggregateType: string
): CommandHandlerMetadata[] {
  const handlers: CommandHandlerMetadata[] = [];

  for (const [_key, metadata] of COMMAND_HANDLERS) {
    if (metadata.aggregateType === aggregateType) {
      handlers.push(metadata);
    }
  }

  return handlers;
}

/**
 * Find command handler by matching HTTP route and method
 *
 * Used by Worker routing layer to find which command to execute
 * based on incoming HTTP request.
 *
 * @param requestPath - HTTP request path (e.g., '/accounts/acc-123/open')
 * @param requestMethod - HTTP method (e.g., 'POST')
 * @returns Command handler metadata or undefined if no match
 *
 * @example
 * ```typescript
 * // Handler registered with route: '/accounts/:id/open'
 * const handler = findHandlerByRoute('/accounts/acc-123/open', 'POST');
 * // Returns: { commandType: 'OpenAccount', methodName: 'openAccount', ... }
 * ```
 */
export function findHandlerByRoute(
  requestPath: string,
  requestMethod: string = 'POST'
): CommandHandlerMetadata | undefined {
  for (const metadata of COMMAND_HANDLERS.values()) {
    const handlerMethod = metadata.method || 'POST';

    if (handlerMethod.toUpperCase() !== requestMethod.toUpperCase()) {
      continue;
    }

    if (matchPath(metadata.route, requestPath)) {
      return metadata;
    }
  }

  return undefined;
}

/**
 * Extract path parameters from request path using route pattern
 *
 * @param routePattern - Route pattern (e.g., '/accounts/:id/withdraw')
 * @param requestPath - Actual request path (e.g., '/accounts/acc-123/withdraw')
 * @returns Object with extracted parameters or null if no match
 *
 * @example
 * ```typescript
 * const params = extractPathParams(
 *   '/accounts/:id/withdraw',
 *   '/accounts/acc-123/withdraw'
 * );
 * // Returns: { id: 'acc-123' }
 * ```
 */
export function extractPathParams(
  routePattern: string,
  requestPath: string
): Record<string, string> | null {
  const patternSegments = routePattern.split('/').filter(Boolean);
  const pathSegments = requestPath.split('/').filter(Boolean);

  if (patternSegments.length !== pathSegments.length) {
    return null;
  }

  const params: Record<string, string> = {};

  for (let i = 0; i < patternSegments.length; i++) {
    const patternSegment = patternSegments[i]!;
    const pathSegment = pathSegments[i]!;

    if (patternSegment.startsWith(':')) {
      const paramName = patternSegment.slice(1);
      params[paramName] = pathSegment;
    } else if (patternSegment !== pathSegment) {
      return null;
    }
  }

  return params;
}

/**
 * Match a request path against a route pattern with parameter support
 *
 * Supports path parameters using :paramName syntax.
 *
 * @param routePattern - Route pattern (e.g., '/accounts/:id/debit')
 * @param requestPath - Actual request path (e.g., '/accounts/acc-123/debit')
 * @returns true if paths match
 *
 * @internal
 */
function matchPath(routePattern: string, requestPath: string): boolean {
  // Simple exact match first
  if (routePattern === requestPath) {
    return true;
  }

  // Split into segments
  const patternSegments = routePattern.split('/').filter(Boolean);
  const pathSegments = requestPath.split('/').filter(Boolean);

  // Must have same number of segments
  if (patternSegments.length !== pathSegments.length) {
    return false;
  }

  // Match each segment
  for (let i = 0; i < patternSegments.length; i++) {
    const patternSegment = patternSegments[i]!;
    const pathSegment = pathSegments[i];

    // Parameter segment (e.g., :id, :aggregateId)
    if (patternSegment.startsWith(':')) {
      continue; // Any value matches a parameter
    }

    // Literal segment must match exactly
    if (patternSegment !== pathSegment) {
      return false;
    }
  }

  return true;
}

/**
 * Clear all registered command handlers
 * FOR TESTING ONLY
 */
export function clearCommandHandlers(): void {
  COMMAND_HANDLERS.clear();
}
